missions', 'Assign platform permissions to user roles.'), (20, 'requests.view-incomplete', 'View incomplete requests', 'View approved requests that are not yet completed.'), (21, 'stock-items.manage', 'Manage stock items addition', 'Manage and approve the addition of stock items to the list of the stock items.'), (22, 'requests.view-audit', 'View audit requests', 'View audit requests page.'), (23, 'technical-inspections.manage', 'Manage technical inspections', 'Create, edit, and delete technical inspection records.'), (136, 'roles.manage', 'Manage roles', 'Create, edit, and delete system roles.'), (137, 'rfx.manage', 'Manage RFX events', 'Publish and manage requests for proposals/quotations.'), (138, 'rfx.respond', 'Respond to RFX events', 'Submit supplier responses to RFQ or RFP events.'), (139, 'risks.view', 'View risk register', 'View organizational risks and mitigations.'), (140, 'risks.manage', 'Manage risks', 'Create and update entries in the risk register.'), (141, 'procure-to-pay.lifecycle.view', 'View procure-to-pay lifecycle', 'View lifecycle, receipts, invoices, matching, finance and payment data for requests.'), (142, 'procure-to-pay.receipts.manage', 'Manage goods receipts', 'Create and update goods receipt events including partial and discrepancy captures.'), (143, 'procure-to-pay.invoices.manage', 'Manage supplier invoices', 'Capture supplier invoices and invoice line details.'), (144, 'procure-to-pay.match.manage', 'Manage invoice matching', 'Run 2-way/3-way invoice matching and review mismatch details.'), (145, 'procure-to-pay.vouchers.manage', 'Manage AP vouchers', 'Create and update AP voucher records in procure-to-pay workflows.'), (146, 'procure-to-pay.payments.manage', 'Manage procure-to-pay payments', 'Track and update payment states for procure-to-pay workflows.'), (147, 'finance.verify', 'Verify finance records', 'Perform finance review and verification before posting.'), (148, 'finance.voucher.create', 'Create AP vouchers', 'Create AP voucher headers and lines within the internal finance module.'), (149, 'finance.post-ledger', 'Post to internal ledger', 'Post verified vouchers to the internal liability recognition state.'), (150, 'finance.payment.manage', 'Manage payment states', 'Mark payment pending and paid states for tracked liabilities.'), (151, 'finance.override-mismatch', 'Override invoice mismatches', 'Approve authorized mismatches with reason codes for audit.'), (163, 'item-master.view', 'View item master', 'Search and view item master records and approved item details.'), (164, 'procure-to-pay.purchase-orders.manage', 'Manage purchase orders', 'Create, edit, submit, approve, issue, and update procure-to-pay purchase orders.'), (165, 'item-master.manage', 'Manage item master records', 'Create and update item master records, metadata, and attachments before approval.'), (166, 'item-master.approve', 'Approve item master records', 'Validate and approve or reject item master records for activation.'), (167, 'requests.mark-urgent-on-submit', 'Mark requests urgent on submission', 'Allows selected requesters to flag a new purchase request as urgent during submission.'), (168, 'approvals.manage', 'Manage approvals', 'Allows privileged users to act as approval managers in request workspaces.'), (169, 'requests.assign', 'Assign requests', 'Allows privileged users to assign procurement requests from the request workspace.');